// Получаем текущий элемент (один из списка)
const item = $input.item.json;

// n8nData — это данные воркфлоу из ветки n8n (обычно Input 2 в Merge)
// gitHubData — это данные из ветки GitHub (Input 1)
// В зависимости от настроек Merge, они могут быть в одном объекте.
// Предположим, Merge объединил их по совпадению или просто передает объект.

const n8nData = item; // Текущий воркфлоу из списка n8n
const gitHubSha = item.sha; // Если Merge нашел совпадение, тут будет SHA
const gitHubPath = item.path;

if (!n8nData.nodes) {
    // Пропускаем, если это "пустой" элемент или только данные GitHub без пары из n8n
    return []; 
}

// Формируем структуру воркфлоу
const updatedWorkflow = {
    id: n8nData.id,
    name: n8nData.name,
    active: n8nData.active,
    nodes: n8nData.nodes,
    connections: n8nData.connections,
    createdAt: n8nData.createdAt || new Date().toISOString(),
    updatedAt: new Date().toISOString()
};

let filePath = gitHubPath || `${n8nData.name}.json`;
let fileExists = !!gitHubSha;

// Кодируем путь
const encodedPath = encodeURIComponent(filePath);
const apiUrl = `https://api.github.com/repos/MarinaKirzner/test_backup/contents/${encodedPath}`;

// Конвертируем в base64
const jsonString = JSON.stringify(updatedWorkflow, null, 2);
const base64Content = Buffer.from(jsonString).toString('base64');

return {
    json: {
        fileExists: fileExists,
        url: apiUrl,
        message: fileExists ? `Update ${n8nData.name}` : `Create backup of ${n8nData.name}`,
        content: base64Content,
        sha: gitHubSha || null,
        branch: 'main',
        workflowName: n8nData.name
    }
};

const items = $input.all();

return items.map(item => {
    let name = item.json.name;
    let compareKey = name;

    // Если в имени есть дата (например, после дефиса начинается 2026...)
    // Улучшенная логика: отрезаем всё, что после последнего дефиса, если там дата
    if (name.includes('-20')) {
        compareKey = name.split('-20')[0].trim();
    } else {
        // Если даты нет, просто убираем .json для чистоты сравнения
        compareKey = name.replace('.json', '');
    }

    return {
        json: {
            ...item.json,
            compareKey: compareKey
        }
    };
});

